-- 20260503041656_mdr_accounts_database.sql
-- Madrasa accounts: database-backed ledger + final Excel import.

create table if not exists public.mdr_account_incomes (
  id text primary key,
  account text not null default 'general' check (account in ('matbakh', 'madrasa', 'tamirat', 'general')),
  hijri_year text,
  month text not null,
  day integer check (day is null or (day between 1 and 30)),
  gregorian_date date,
  amount numeric(14,2) not null check (amount >= 0),
  note text not null default '',
  source_file text,
  source_sheet text,
  source_row integer,
  metadata jsonb not null default '{}'::jsonb,
  created_by uuid references public.shared_users(id),
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);
create table if not exists public.mdr_account_expenses (
  id text primary key,
  account text not null check (account in ('matbakh', 'madrasa', 'tamirat', 'general')),
  project text,
  hijri_year text,
  month text not null,
  day integer check (day is null or (day between 1 and 30)),
  gregorian_date date,
  category text,
  description text not null default '',
  quantity numeric(14,3),
  unit text,
  unit_price numeric(14,4),
  amount numeric(14,2) not null check (amount >= 0),
  supplier text,
  receipt_no text,
  payment_method text,
  source_file text,
  source_sheet text,
  source_row integer,
  metadata jsonb not null default '{}'::jsonb,
  created_by uuid references public.shared_users(id),
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);
create table if not exists public.mdr_account_dues (
  id text primary key,
  account text not null check (account in ('matbakh', 'madrasa', 'tamirat', 'general')),
  supplier text not null,
  total numeric(14,2) not null default 0 check (total >= 0),
  paid numeric(14,2) not null default 0 check (paid >= 0),
  due numeric(14,2) not null default 0,
  source_file text,
  source_sheet text,
  source_row integer,
  metadata jsonb not null default '{}'::jsonb,
  created_by uuid references public.shared_users(id),
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);
create table if not exists public.mdr_account_due_payments (
  id text primary key,
  due_id text references public.mdr_account_dues(id) on delete set null,
  account text not null check (account in ('matbakh', 'madrasa', 'tamirat', 'general')),
  supplier text not null,
  hijri_year text,
  month text,
  day integer check (day is null or (day between 1 and 30)),
  gregorian_date date,
  raw_date text,
  amount numeric(14,2) not null check (amount >= 0),
  receipt_no text,
  source_file text,
  source_sheet text,
  source_row integer,
  metadata jsonb not null default '{}'::jsonb,
  created_by uuid references public.shared_users(id),
  created_at timestamptz not null default now()
);
create table if not exists public.mdr_account_categories (
  name text primary key,
  created_by uuid references public.shared_users(id),
  created_at timestamptz not null default now()
);
create index if not exists mdr_account_incomes_month_idx on public.mdr_account_incomes (hijri_year, month, day);
create index if not exists mdr_account_expenses_account_month_idx on public.mdr_account_expenses (account, hijri_year, month, day);
create index if not exists mdr_account_expenses_supplier_idx on public.mdr_account_expenses (lower(coalesce(supplier, '')));
create unique index if not exists mdr_account_dues_account_supplier_key on public.mdr_account_dues (account, lower(supplier));
alter table public.mdr_account_incomes enable row level security;
alter table public.mdr_account_expenses enable row level security;
alter table public.mdr_account_dues enable row level security;
alter table public.mdr_account_due_payments enable row level security;
alter table public.mdr_account_categories enable row level security;
drop policy if exists "deny_all_mdr_account_incomes" on public.mdr_account_incomes;
create policy "deny_all_mdr_account_incomes" on public.mdr_account_incomes for all using (false) with check (false);
drop policy if exists "deny_all_mdr_account_expenses" on public.mdr_account_expenses;
create policy "deny_all_mdr_account_expenses" on public.mdr_account_expenses for all using (false) with check (false);
drop policy if exists "deny_all_mdr_account_dues" on public.mdr_account_dues;
create policy "deny_all_mdr_account_dues" on public.mdr_account_dues for all using (false) with check (false);
drop policy if exists "deny_all_mdr_account_due_payments" on public.mdr_account_due_payments;
create policy "deny_all_mdr_account_due_payments" on public.mdr_account_due_payments for all using (false) with check (false);
drop policy if exists "deny_all_mdr_account_categories" on public.mdr_account_categories;
create policy "deny_all_mdr_account_categories" on public.mdr_account_categories for all using (false) with check (false);
create or replace function private.mdr_account_actor(
  p_actor_id uuid,
  p_pin text,
  p_allow_admin boolean default true
)
returns public.shared_users
language plpgsql
security definer
set search_path = public, private
as $$
declare
  v_actor public.shared_users%rowtype;
begin
  select * into v_actor
  from public.shared_users u
  where u.is_active = true
    and u.pin = p_pin
    and (p_actor_id is null or u.id = p_actor_id)
    and (
      u.role = 'daftar'
      or (p_allow_admin and u.role = 'admin')
    )
  order by case when p_actor_id is not null and u.id = p_actor_id then 0 else 1 end, u.created_at
  limit 1;

  return v_actor;
end;
$$;
create or replace function public.mdr_rel_accounts_bootstrap(p_actor_id uuid, p_pin text)
returns jsonb
language plpgsql
security definer
set search_path = public, private
as $$
declare
  v_actor public.shared_users%rowtype;
begin
  v_actor := private.mdr_account_actor(p_actor_id, p_pin, true);
  if v_actor.id is null then
    return jsonb_build_object('ok', false, 'error', 'invalid_actor');
  end if;

  return jsonb_build_object(
    'ok', true,
    'read_only', v_actor.role = 'admin',
    'incomes', coalesce((
      select jsonb_agg(jsonb_build_object(
        'id', i.id,
        'account', i.account,
        'hijriYear', i.hijri_year,
        'month', i.month,
        'day', i.day,
        'date', coalesce(i.gregorian_date::text, ''),
        'amount', i.amount,
        'note', i.note,
        'sourceFile', i.source_file,
        'sourceSheet', i.source_sheet,
        'sourceRow', i.source_row,
        '_at', floor(extract(epoch from i.created_at) * 1000)::bigint,
        '_updatedAt', floor(extract(epoch from i.updated_at) * 1000)::bigint
      ) order by i.hijri_year, i.month, i.day, i.id)
      from public.mdr_account_incomes i
    ), '[]'::jsonb),
    'expenses', coalesce((
      select jsonb_agg(jsonb_build_object(
        'id', e.id,
        'account', e.account,
        'project', e.project,
        'hijriYear', e.hijri_year,
        'month', e.month,
        'day', e.day,
        'date', coalesce(e.gregorian_date::text, ''),
        'category', e.category,
        'description', e.description,
        'quantity', e.quantity,
        'unit', e.unit,
        'unitPrice', e.unit_price,
        'amount', e.amount,
        'supplier', e.supplier,
        'receiptNo', e.receipt_no,
        'paymentMethod', e.payment_method,
        'sourceFile', e.source_file,
        'sourceSheet', e.source_sheet,
        'sourceRow', e.source_row,
        '_at', floor(extract(epoch from e.created_at) * 1000)::bigint,
        '_updatedAt', floor(extract(epoch from e.updated_at) * 1000)::bigint
      ) order by e.hijri_year, e.month, e.day, e.id)
      from public.mdr_account_expenses e
    ), '[]'::jsonb),
    'dues', coalesce((
      select jsonb_agg(jsonb_build_object(
        'id', d.id,
        'account', d.account,
        'supplier', d.supplier,
        'total', d.total,
        'paid', d.paid,
        'due', d.due,
        'sourceFile', d.source_file,
        'sourceSheet', d.source_sheet,
        'sourceRow', d.source_row
      ) order by d.account, d.supplier)
      from public.mdr_account_dues d
    ), '[]'::jsonb),
    'duePayments', coalesce((
      select jsonb_agg(jsonb_build_object(
        'id', p.id,
        'dueId', p.due_id,
        'account', p.account,
        'supplier', p.supplier,
        'hijriYear', p.hijri_year,
        'month', p.month,
        'day', p.day,
        'date', coalesce(p.gregorian_date::text, ''),
        'rawDate', p.raw_date,
        'amount', p.amount,
        'receiptNo', p.receipt_no,
        'sourceFile', p.source_file,
        'sourceSheet', p.source_sheet,
        'sourceRow', p.source_row
      ) order by p.created_at, p.id)
      from public.mdr_account_due_payments p
    ), '[]'::jsonb),
    'categories', coalesce((select jsonb_agg(c.name order by c.name) from public.mdr_account_categories c), '[]'::jsonb)
  );
end;
$$;
create or replace function public.mdr_rel_account_upsert_income(p_actor_id uuid, p_pin text, p_entry jsonb)
returns jsonb
language plpgsql
security definer
set search_path = public, private
as $$
declare
  v_actor public.shared_users%rowtype;
  v_id text;
begin
  v_actor := private.mdr_account_actor(p_actor_id, p_pin, false);
  if v_actor.id is null then return jsonb_build_object('ok', false, 'error', 'invalid_actor'); end if;
  if p_entry is null or jsonb_typeof(p_entry) <> 'object' then return jsonb_build_object('ok', false, 'error', 'invalid_payload'); end if;

  v_id := coalesce(nullif(p_entry->>'id', ''), 'inc-' || replace(gen_random_uuid()::text, '-', ''));
  insert into public.mdr_account_incomes (id, account, hijri_year, month, day, gregorian_date, amount, note, source_file, source_sheet, source_row, metadata, created_by, updated_at)
  values (
    v_id,
    coalesce(nullif(p_entry->>'account', ''), 'general'),
    nullif(p_entry->>'hijriYear', ''),
    nullif(p_entry->>'month', ''),
    nullif(p_entry->>'day', '')::integer,
    nullif(p_entry->>'date', '')::date,
    greatest(coalesce((p_entry->>'amount')::numeric, 0), 0),
    coalesce(p_entry->>'note', ''),
    nullif(p_entry->>'sourceFile', ''),
    nullif(p_entry->>'sourceSheet', ''),
    nullif(p_entry->>'sourceRow', '')::integer,
    coalesce(p_entry - array['id','account','hijriYear','month','day','date','amount','note','sourceFile','sourceSheet','sourceRow'], '{}'::jsonb),
    v_actor.id,
    now()
  )
  on conflict (id) do update set
    account = excluded.account,
    hijri_year = excluded.hijri_year,
    month = excluded.month,
    day = excluded.day,
    gregorian_date = excluded.gregorian_date,
    amount = excluded.amount,
    note = excluded.note,
    source_file = coalesce(excluded.source_file, public.mdr_account_incomes.source_file),
    source_sheet = coalesce(excluded.source_sheet, public.mdr_account_incomes.source_sheet),
    source_row = coalesce(excluded.source_row, public.mdr_account_incomes.source_row),
    metadata = public.mdr_account_incomes.metadata || excluded.metadata,
    updated_at = now();

  return jsonb_build_object('ok', true, 'id', v_id, 'entry', (select to_jsonb(x) from public.mdr_account_incomes x where x.id = v_id));
end;
$$;
create or replace function public.mdr_rel_account_upsert_expense(p_actor_id uuid, p_pin text, p_entry jsonb)
