$$;
create or replace function public.mdr_rel_account_delete_entry(p_actor_id uuid, p_pin text, p_type text, p_id text)
returns jsonb
language plpgsql
security definer
set search_path = public, private
as $$
declare
  v_actor public.shared_users%rowtype;
  v_deleted int;
begin
  v_actor := private.mdr_account_actor(p_actor_id, p_pin, false);
  if v_actor.id is null then return jsonb_build_object('ok', false, 'error', 'invalid_actor'); end if;

  if p_type = 'income' then
    delete from public.mdr_account_incomes where id = p_id;
  elsif p_type = 'expense' then
    delete from public.mdr_account_expenses where id = p_id;
  else
    return jsonb_build_object('ok', false, 'error', 'invalid_type');
  end if;
  get diagnostics v_deleted = ROW_COUNT;
  if v_deleted < 1 then return jsonb_build_object('ok', false, 'error', 'not_found'); end if;
  return jsonb_build_object('ok', true);
end;
$$;
create or replace function public.mdr_rel_account_adjust_due_purchase(
  p_actor_id uuid,
  p_pin text,
  p_supplier text,
  p_account text,
  p_amount_delta numeric
)
returns jsonb
language plpgsql
security definer
set search_path = public, private
as $$
declare
  v_actor public.shared_users%rowtype;
  v_supplier text := nullif(btrim(coalesce(p_supplier, '')), '');
  v_account text := coalesce(nullif(btrim(coalesce(p_account, '')), ''), 'general');
  v_id text;
begin
  v_actor := private.mdr_account_actor(p_actor_id, p_pin, false);
  if v_actor.id is null then return jsonb_build_object('ok', false, 'error', 'invalid_actor'); end if;
  if v_supplier is null or coalesce(p_amount_delta, 0) = 0 then return jsonb_build_object('ok', true); end if;

  v_id := 'due-' || substr(md5(v_account || ':' || lower(v_supplier)), 1, 20);
  insert into public.mdr_account_dues (id, account, supplier, total, paid, due, created_by, updated_at)
  values (v_id, v_account, v_supplier, greatest(coalesce(p_amount_delta, 0), 0), 0, greatest(coalesce(p_amount_delta, 0), 0), v_actor.id, now())
  on conflict (account, lower(supplier)) do update set
    total = greatest(public.mdr_account_dues.total + coalesce(p_amount_delta, 0), 0),
    due = greatest(public.mdr_account_dues.total + coalesce(p_amount_delta, 0), 0) - public.mdr_account_dues.paid,
    updated_at = now()
  returning id into v_id;

  return jsonb_build_object('ok', true, 'id', v_id);
end;
$$;
create or replace function public.mdr_rel_account_record_due_payment(
  p_actor_id uuid,
  p_pin text,
  p_due_id text,
  p_amount numeric
)
returns jsonb
language plpgsql
security definer
set search_path = public, private
as $$
declare
  v_actor public.shared_users%rowtype;
  v_due public.mdr_account_dues%rowtype;
  v_id text;
begin
  v_actor := private.mdr_account_actor(p_actor_id, p_pin, false);
  if v_actor.id is null then return jsonb_build_object('ok', false, 'error', 'invalid_actor'); end if;
  if coalesce(p_amount, 0) <= 0 then return jsonb_build_object('ok', false, 'error', 'amount_required'); end if;

  select * into v_due from public.mdr_account_dues where id = p_due_id;
  if v_due.id is null then return jsonb_build_object('ok', false, 'error', 'due_not_found'); end if;

  update public.mdr_account_dues
  set paid = paid + p_amount,
      due = total - (paid + p_amount),
      updated_at = now()
  where id = p_due_id;

  v_id := 'pay-' || replace(gen_random_uuid()::text, '-', '');
  insert into public.mdr_account_due_payments (id, due_id, account, supplier, amount, created_by)
  values (v_id, p_due_id, v_due.account, v_due.supplier, p_amount, v_actor.id);

  return jsonb_build_object('ok', true, 'id', v_id);
end;
$$;
create or replace function public.mdr_rel_account_add_category(p_actor_id uuid, p_pin text, p_name text)
returns jsonb
language plpgsql
security definer
set search_path = public, private
as $$
declare
  v_actor public.shared_users%rowtype;
  v_name text := nullif(btrim(coalesce(p_name, '')), '');
begin
  v_actor := private.mdr_account_actor(p_actor_id, p_pin, false);
  if v_actor.id is null then return jsonb_build_object('ok', false, 'error', 'invalid_actor'); end if;
  if v_name is null then return jsonb_build_object('ok', false, 'error', 'name_required'); end if;
  insert into public.mdr_account_categories (name, created_by) values (v_name, v_actor.id) on conflict (name) do nothing;
  return jsonb_build_object('ok', true);
end;
$$;
create or replace function public.mdr_rel_account_delete_category(p_actor_id uuid, p_pin text, p_name text)
returns jsonb
language plpgsql
security definer
set search_path = public, private
as $$
declare
  v_actor public.shared_users%rowtype;
begin
  v_actor := private.mdr_account_actor(p_actor_id, p_pin, false);
  if v_actor.id is null then return jsonb_build_object('ok', false, 'error', 'invalid_actor'); end if;
  delete from public.mdr_account_categories where name = p_name;
  return jsonb_build_object('ok', true);
end;
$$;
grant execute on function public.mdr_rel_accounts_bootstrap(uuid, text) to anon;
grant execute on function public.mdr_rel_account_upsert_income(uuid, text, jsonb) to anon;
grant execute on function public.mdr_rel_account_upsert_expense(uuid, text, jsonb) to anon;
grant execute on function public.mdr_rel_account_delete_entry(uuid, text, text, text) to anon;
grant execute on function public.mdr_rel_account_adjust_due_purchase(uuid, text, text, text, numeric) to anon;
grant execute on function public.mdr_rel_account_record_due_payment(uuid, text, text, numeric) to anon;
grant execute on function public.mdr_rel_account_add_category(uuid, text, text) to anon;
grant execute on function public.mdr_rel_account_delete_category(uuid, text, text) to anon;
