insert into public.mdr_account_incomes (id, account, hijri_year, month, day, gregorian_date, amount, note, source_file, source_sheet, source_row, metadata)
select
  r.id,
  coalesce(nullif(r.account, ''), 'general'),
  nullif(r."hijriYear", ''),
  r.month,
