insert into public.mdr_account_dues (id, account, supplier, total, paid, due, source_file, source_sheet, source_row, metadata)
select
  r.id,
  coalesce(nullif(r.account, ''), 'general'),
  r.supplier,
  coalesce(r.total, 0),
  coalesce(r.paid, 0),
  coalesce(r.due, coalesce(r.total, 0) - coalesce(r.paid, 0)),
  nullif(r."sourceFile", ''),
  nullif(r."sourceSheet", ''),
  r."sourceRow",
  '{}'::jsonb
from payload p,
jsonb_to_recordset(p.doc->'dues') as r(
  id text, "sourceFile" text, "sourceSheet" text, "sourceRow" integer, account text,
  supplier text, total numeric, paid numeric, due numeric
)
on conflict (id) do update set
  account = excluded.account,
  supplier = excluded.supplier,
  total = excluded.total,
  paid = excluded.paid,
  due = excluded.due,
  source_file = excluded.source_file,
  source_sheet = excluded.source_sheet,
  source_row = excluded.source_row,
  updated_at = now();
