"à¦¬à¦¨à§à¦§à§ à¦Ÿà§à¦°à§‡à¦¡à¦¾à¦°à§à¦¸","receiptNo":"65"},{"id":"pay-00013","sourceFile":"à¦¤à¦¾à¦®à¦¿à¦°à¦¾à¦¤.xlsx","sourceSheet":"à¦¬à¦•à§‡à§Ÿà¦¾","sourceRow":13,"account":"tamirat","date":"2026-04-28","amount":20000,"supplier":"à¦†à¦¨à§‹à§Ÿà¦¾à¦°","receiptNo":""}]}$mmacc$::jsonb as doc
), rows as (
  select r.*
  from payload p,
  jsonb_to_recordset(coalesce(p.doc->'duePayments', '[]'::jsonb)) as r(
    id text, "sourceFile" text, "sourceSheet" text, "sourceRow" integer, account text,
    date text, amount numeric, supplier text, "receiptNo" text
  )
)
insert into public.mdr_account_due_payments (id, due_id, account, supplier, raw_date, amount, receipt_no, source_file, source_sheet, source_row, metadata)
select
  rows.id,
  d.id,
  coalesce(nullif(rows.account, ''), d.account, 'general'),
  rows.supplier,
  nullif(rows.date, ''),
  coalesce(rows.amount, 0),
  nullif(rows."receiptNo", ''),
  nullif(rows."sourceFile", ''),
  nullif(rows."sourceSheet", ''),
  rows."sourceRow",
  '{}'::jsonb
from rows
left join public.mdr_account_dues d
  on d.account = coalesce(nullif(rows.account, ''), d.account)
 and lower(d.supplier) = lower(rows.supplier)
on conflict (id) do update set
  due_id = excluded.due_id,
  account = excluded.account,
  supplier = excluded.supplier,
  raw_date = excluded.raw_date,
  amount = excluded.amount,
  receipt_no = excluded.receipt_no,
  source_file = excluded.source_file,
  source_sheet = excluded.source_sheet,
  source_row = excluded.source_row;
